import { Controller, Get, Query } from '@nestjs/common';
import { ApiOperation, ApiResponse, ApiTags } from '@nestjs/swagger';

import { FrequentlyBoughtTogetherService } from '@modules/rest/frequently-bought-together/frequently-bought-together.service';

import { LogExecution } from '@decorators/log-execution.decorator';

import { FrequentlyBoughtTogetherQueryDto } from '@dto/frequently-bought-together/frequently-bought-together-query.dto';
import { FrequentlyBoughtTogetherResponseDto } from '@dto/frequently-bought-together/frequently-bought-together-response.dto';
import { FrequentlyBoughtTogetherRootCategoriesQueryDto } from '@dto/frequently-bought-together/frequently-bought-together-root-categories-query.dto';
import { FrequentlyBoughtTogetherRootCategoriesResponseDto } from '@dto/frequently-bought-together/frequently-bought-together-root-categories-response.dto';
import { FrequentlyBoughtTogetherV2QueryDto } from '@dto/frequently-bought-together/frequently-bought-together-v2-query.dto';
import { FrequentlyBoughtTogetherV2ResponseDto } from '@dto/frequently-bought-together/frequently-bought-together-v2-response.dto';

@ApiTags('Frequently Bought Together')
@Controller('frequently-bought-together')
export class FrequentlyBoughtTogetherController {
	constructor(
		private readonly frequentlyBoughtTogetherService: FrequentlyBoughtTogetherService,
	) {}

	@Get()
	@ApiOperation({
		summary: 'Get frequently bought together products for a style and color',
	})
	@ApiResponse({
		status: 200,
		description: 'Returns frequently bought together products',
		type: FrequentlyBoughtTogetherResponseDto,
	})
	@ApiResponse({ status: 400, description: 'Bad request - invalid parameters' })
	@ApiResponse({ status: 500, description: 'Internal server error' })
	@LogExecution({
		paramFormatter: ([query]: [FrequentlyBoughtTogetherQueryDto]) => ({
			styleIds: query.styleIds,
			styleIdsCount: query.styleIds.length,
			excludeCount: query.exclude?.length ?? 0,
		}),

		responseFormatter: (res: FrequentlyBoughtTogetherResponseDto) => ({
			count: res.frequently_bought_together.length,
			fallbackUsed: res.fallback_used,
		}),
	})
	async getFrequentlyBoughtTogether(
		@Query() query: FrequentlyBoughtTogetherQueryDto,
	): Promise<FrequentlyBoughtTogetherResponseDto> {
		return this.frequentlyBoughtTogetherService.getFrequentlyBoughtTogether(query);
	}

	@Get('root-categories')
	@ApiOperation({
		summary:
			'Get frequently bought together products for a style and color by root categories',
	})
	@ApiResponse({
		status: 200,
		description: 'Returns frequently bought together products by root categories',
		type: FrequentlyBoughtTogetherRootCategoriesResponseDto,
	})
	@ApiResponse({ status: 400, description: 'Bad request - invalid parameters' })
	@ApiResponse({ status: 500, description: 'Internal server error' })
	@LogExecution({
		paramFormatter: ([query]: [FrequentlyBoughtTogetherRootCategoriesQueryDto]) => ({
			styleIds: query.styleIds,
			styleIdsCount: query.styleIds.length,
			excludeCount: query.exclude?.length ?? 0,
		}),

		responseFormatter: (res: FrequentlyBoughtTogetherRootCategoriesResponseDto) => ({
			count: res.frequently_bought_together.length,
			fallbackUsed: res.fallback_used,
		}),
	})
	async getFrequentlyBoughtTogetherByRootCategories(
		@Query() query: FrequentlyBoughtTogetherRootCategoriesQueryDto,
	): Promise<FrequentlyBoughtTogetherRootCategoriesResponseDto> {
		return this.frequentlyBoughtTogetherService.getFrequentlyBoughtTogetherByRootCategories(
			query,
		);
	}

	@Get('v2')
	@ApiOperation({
		summary: 'Get frequently bought together products using co-purchase data',
	})
	@ApiResponse({
		status: 200,
		description: 'Returns co-purchased products for a style',
		type: FrequentlyBoughtTogetherV2ResponseDto,
	})
	@ApiResponse({ status: 400, description: 'Bad request - invalid parameters' })
	@ApiResponse({ status: 500, description: 'Internal server error' })
	@LogExecution({
		paramFormatter: ([query]: [FrequentlyBoughtTogetherV2QueryDto]) => ({
			styleId: query.styleId,
			limit: query.limit,
			diversifyCategories: query.diversifyCategories,
			favorOppositeType: query.favorOppositeType,
		}),

		responseFormatter: (res: FrequentlyBoughtTogetherV2ResponseDto) => ({
			count: res?.frequently_bought_together?.length ?? 0,
			fallbackUsed: res?.fallback_used ?? false,
		}),
	})
	async getFrequentlyBoughtTogetherV2(
		@Query() query: FrequentlyBoughtTogetherV2QueryDto,
	): Promise<FrequentlyBoughtTogetherV2ResponseDto> {
		return this.frequentlyBoughtTogetherService.getFrequentlyBoughtTogetherV2(query);
	}
}

