import * as os from 'os';
import * as path from 'path';
import { Worker, WorkerOptions } from 'worker_threads';

import { Logger } from '@nestjs/common';
import { Command, CommandRunner, Option } from 'nest-commander';

import { bufferedRollbar } from '@config/rollbar-buffer.config';

import { IProductAnnualSalesBase } from '@modules/db/product-annual-sales/types/product-annual-sales.base.interface';
import { RenderTrendingResultsService } from '@modules/rest/trending-products/render-trending-results.service';
import { TrendingProductsService } from '@modules/rest/trending-products/trending-products.service';

import { ProgressBar } from '@utils/progress-bar.util';

import { CompleteForecastResult } from '@interfaces/trending-products.interface';

import { CronJobExecution } from '@decorators/cron-job-execution.decorator';

type ForecastOptions = [string, string, string, string, string];

interface WorkerResult {
	success: boolean;
	results?: CompleteForecastResult[];
	error?: string;
}

@Command({
	name: 'forecast-trending-products',
	description:
		'Analyze historical data and forecast trends for products for the next 7 days',
})
export class ForecastTrendingProductsCommand extends CommandRunner {
	private readonly logger = new Logger(ForecastTrendingProductsCommand.name);
	private readonly FORECAST_DAYS = 9;
	private readonly PARALLEL_WORKERS = Math.min(os.cpus().length, 8);
	private readonly BATCH_SIZE_PER_WORKER = 5;

	constructor(
		private readonly trendingProductsService: TrendingProductsService,
		private readonly renderTrendingResultsService: RenderTrendingResultsService,
	) {
		super();
	}

	@Option({
		flags: '-s, --start-date [string]',
		description: 'Start date for analysis (YYYY-MM-DD)',
	})
	parseStartDate(val: string): string {
		return val;
	}

	@Option({
		flags: '-e, --end-date [string]',
		description: 'End date for analysis (YYYY-MM-DD)',
	})
	parseEndDate(val: string): string {
		return val;
	}

	@Option({
		flags: '-p, --products [string]',
		description: 'Comma-separated list of style_ids to analyze',
	})
	parseProducts(val: string): string {
		return val;
	}

	@Option({
		flags: '-b, --batch-size [number]',
		description: 'Batch size for processing',
	})
	parseBatchSize(val: string): number {
		return parseInt(val, 10);
	}

	@Option({
		flags: '-f, --forecast-days [number]',
		description: 'Number of days to forecast (default: 9)',
	})
	parseForecastDays(val: string): number {
		return parseInt(val, 10) || this.FORECAST_DAYS;
	}

	@CronJobExecution({ jobName: 'forecast-trending-products' })
	async run(passedParam: ForecastOptions): Promise<void> {
		// TODO: need to use named parameters from options, not as indexed params from passedParam
		const startDate = passedParam[0] || this.getDefaultStartDate();
		const endDate = passedParam[1] || this.getDefaultEndDate();
		const forecastDays = passedParam[4]
			? parseInt(passedParam[4], 10)
			: this.FORECAST_DAYS;

		this.logger.log(`Forecasting trends from ${startDate} to ${endDate}`);

		await this.trendingProductsService.invalidateLatestForecasts();

		const productsData = await this.trendingProductsService.getStyleIdsInDateRange({
			startDate,
			endDate,
		});

		const productIds = productsData.reduce<number[]>((acc, product) => {
			if (!acc.includes(product.style_id)) {
				acc.push(product.style_id);
			}
			return acc;
		}, []);

		this.logger.log(`Found ${productIds.length} products with historical data`);

		if (productIds.length === 0) {
			this.logger.warn(
				'No products found with historical data in the specified date range',
			);
			return;
		}

		const totalProducts = productIds.length;

		const bar = new ProgressBar({ total: totalProducts });

		const allResults = await this.processProductsInParallel({
			productIds,
			productsData,
			startDate,
			endDate,
			forecastDays,
			bar,
		});

		this.logger.log(
			`Forecast completed. Processing ${allResults.length} results for database save.`,
		);

		const filtered = allResults
			.filter((res) => res.predicted_orders.reduce((a, b) => a + b, 0) > 10)
			.sort((a, b) => b.trend_score - a.trend_score);

		const top30Results = filtered.slice(0, 30);

		this.logger.log(
			`Generating detailed HTML reports for top ${top30Results.length} trending products...`,
		);
		await this.renderTrendingResultsService.generateDetailedTrendingProductsReports({
			forecastResults: top30Results,
		});

		this.logger.log('Activating latest predictions...');
		await this.trendingProductsService.activateLatestPredictions();

		this.logger.log('Forecast and report generation completed successfully');
	}

	private async processProductsInParallel({
		productIds,
		productsData,
		startDate,
		endDate,
		forecastDays,
		bar,
	}: {
		productIds: number[];
		productsData: IProductAnnualSalesBase[];
		startDate: string;
		endDate: string;
		forecastDays: number;
		bar: ProgressBar;
	}): Promise<CompleteForecastResult[]> {
		const allResults: CompleteForecastResult[] = [];
		const batchSize = this.BATCH_SIZE_PER_WORKER;
		let processedCount = 0;

		const batches: {
			styleId: number;
			historicalData: IProductAnnualSalesBase[];
		}[][] = [];
		for (let i = 0; i < productIds.length; i += batchSize) {
			const batch = productIds
				.slice(i, Math.min(i + batchSize, productIds.length))
				.map((styleId) => ({
					styleId,
					historicalData: productsData.filter((item) => item.style_id === styleId),
				}));
			batches.push(batch);
		}

		this.logger.log(
			`Processing ${productIds.length} products in ${batches.length} batches using ${this.PARALLEL_WORKERS} workers`,
		);

		for (let i = 0; i < batches.length; i += this.PARALLEL_WORKERS) {
			const batchChunk = batches.slice(
				i,
				Math.min(i + this.PARALLEL_WORKERS, batches.length),
			);

			const chunkPromises = batchChunk.map((batch) =>
				this.processInWorker({
					batch,
					startDate,
					endDate,
					forecastDays,
				}),
			);

			const chunkResults = await Promise.allSettled(chunkPromises);

			for (let j = 0; j < chunkResults.length; j++) {
				const result = chunkResults[j];
				const batch = batchChunk[j];

				if (!result || !batch) continue;

				if (result.status === 'fulfilled') {
					const workerResult = result.value;
					if (workerResult.success && workerResult.results) {
						allResults.push(...workerResult.results);

						if (workerResult.results.length > 0) {
							try {
								await this.trendingProductsService.saveBatchResults({
									results: workerResult.results,
									startDate,
									endDate,
									forecastDays,
								});
								this.logger.log(
									`Saved ${workerResult.results.length} results to database`,
								);
							} catch (error) {
								const err = error instanceof Error ? error : new Error(String(error));
								this.logger.error(`Failed to save batch results: ${err.message}`);
								bufferedRollbar.error({
									err,
									context: {
										operation: 'saveBatchResults',
										batchSize: workerResult.results.length,
									},
								});
							}
						}
					}
				} else {
					this.logger.error(`Worker batch failed: ${result.reason}`);
					bufferedRollbar.error({
						err: new Error(`Worker batch failed: ${result.reason}`),
						context: {
							operation: 'processInWorker',
							batchSize: batch.length,
						},
					});
				}

				processedCount += batch.length;
				bar.increment({ by: batch.length });
				this.logger.log(
					`Progress: ${processedCount}/${productIds.length} products processed`,
				);
			}
		}

		bar.finish();
		return allResults;
	}

	private processInWorker({
		batch,
		startDate,
		endDate,
		forecastDays,
	}: {
		batch: { styleId: number; historicalData: IProductAnnualSalesBase[] }[];
		startDate: string;
		endDate: string;
		forecastDays: number;
	}): Promise<WorkerResult> {
		return new Promise((resolve, reject) => {
			const isDevelopment = process.env['NODE_ENV'] === 'development';
			let workerPath: string;
			if (isDevelopment) {
				workerPath = path.resolve(__dirname, '..', 'workers', 'forecast-worker.ts');
			} else {
				workerPath = path.resolve(__dirname, '..', 'workers', 'forecast-worker.js');
			}

			const workerOptions: WorkerOptions = {
				workerData: {
					batch,
					startDate,
					endDate,
					forecastDays,
				},
			};

			if (isDevelopment) {
				workerOptions.execArgv = [
					'-r',
					'ts-node/register',
					'-r',
					'tsconfig-paths/register',
				];
			}

			const worker = new Worker(workerPath, workerOptions);
			let resolved = false;

			const cleanup = () => {
				if (!resolved) {
					resolved = true;
					worker.terminate().catch(() => {
						// Ignore termination errors
					});
				}
			};

			const timeout = setTimeout(() => {
				cleanup();
				reject(new Error('Worker timeout after 60 seconds'));
			}, 60000);

			worker.on('message', (result: WorkerResult) => {
				clearTimeout(timeout);
				cleanup();
				resolve(result);
			});

			worker.on('error', (error) => {
				clearTimeout(timeout);
				cleanup();
				reject(error);
			});

			worker.on('exit', (code) => {
				clearTimeout(timeout);
				if (code !== 0 && !resolved) {
					cleanup();
					reject(new Error(`Worker stopped with exit code ${code}`));
				}
			});
		});
	}

	private getDefaultStartDate(): string {
		const date = new Date();
		date.setFullYear(date.getFullYear() - 1);
		return date.toISOString().split('T')[0] ?? '';
	}

	private getDefaultEndDate(): string {
		const date = new Date();
		date.setDate(date.getDate() - 2);
		return date.toISOString().split('T')[0] ?? '';
	}
}

import { Test, TestingModule } from '@nestjs/testing';

import { BigQueryService } from '@modules/bigquery/bigquery.service';
import { EnvConfigService } from '@modules/env-config/env-config.service';

import { BIGQUERY_ORDERS_TABLE } from '@constants/bigquery.constant';

import { StyleCopurchaseRow } from '@interfaces/style-copurchase.interface';

const mockQuery = jest.fn();

jest.mock('@google-cloud/bigquery', () => ({
	BigQuery: jest.fn().mockImplementation(() => ({
		query: mockQuery,
	})),
}));

jest.mock('@config/rollbar.config', () => ({
	rollbar: {
		debug: jest.fn(),
		error: jest.fn(),
		warning: jest.fn(),
		info: jest.fn(),
	},
}));

const fakeCredentials = {
	project_id: 'test-project',
	client_email: 'test@test.iam.gserviceaccount.com',
	private_key: 'fake-key',
};

const base64Key = Buffer.from(JSON.stringify(fakeCredentials)).toString('base64');

describe('BigQueryService', () => {
	let service: BigQueryService;

	const mockEnvConfigService = {
		get: jest.fn().mockReturnValue(base64Key),
	};

	beforeEach(async () => {
		jest.clearAllMocks();
		mockEnvConfigService.get.mockReturnValue(base64Key);

		const module: TestingModule = await Test.createTestingModule({
			providers: [
				BigQueryService,
				{ provide: EnvConfigService, useValue: mockEnvConfigService },
			],
		}).compile();

		service = module.get<BigQueryService>(BigQueryService);
		service.onModuleInit();
	});

	describe('onModuleInit', () => {
		it('should initialize BigQuery client with decoded credentials', () => {
			const { BigQuery } =
				// eslint-disable-next-line @typescript-eslint/no-require-imports
				require('@google-cloud/bigquery') as { BigQuery: jest.Mock };

			expect(BigQuery).toHaveBeenCalledWith({
				projectId: 'test-project',
				credentials: fakeCredentials,
			});
		});

		it('should throw and log error when base64 key is invalid', async () => {
			mockEnvConfigService.get.mockReturnValue('not-valid-base64!!!');

			const module: TestingModule = await Test.createTestingModule({
				providers: [
					BigQueryService,
					{ provide: EnvConfigService, useValue: mockEnvConfigService },
				],
			}).compile();

			const badService = module.get<BigQueryService>(BigQueryService);

			expect(() => {
				badService.onModuleInit();
			}).toThrow();
		});

		it('should throw and log error when JSON is malformed', async () => {
			const invalidJson = Buffer.from('not json').toString('base64');
			mockEnvConfigService.get.mockReturnValue(invalidJson);

			const module: TestingModule = await Test.createTestingModule({
				providers: [
					BigQueryService,
					{ provide: EnvConfigService, useValue: mockEnvConfigService },
				],
			}).compile();

			const badService = module.get<BigQueryService>(BigQueryService);

			expect(() => {
				badService.onModuleInit();
			}).toThrow();
		});
	});

	describe('fetchStyleCopurchases', () => {
		it('should return mapped co-purchase rows', async () => {
			const mockRows = [
				{ style_a_id: 100, style_b_id: 200, co_purchase_count: 5 },
				{ style_a_id: 300, style_b_id: 400, co_purchase_count: 3 },
			];
			mockQuery.mockResolvedValueOnce([mockRows]);

			const result = await service.fetchStyleCopurchases();

			expect(result).toEqual([
				{ style_a_id: 100, style_b_id: 200, co_purchase_count: 5 },
				{ style_a_id: 300, style_b_id: 400, co_purchase_count: 3 },
			]);
			expect(mockQuery).toHaveBeenCalledWith({
				query: expect.stringContaining('order_styles') as string,
			});
		});

		it('should return empty array when no rows', async () => {
			mockQuery.mockResolvedValueOnce([[]]);

			const result = await service.fetchStyleCopurchases();

			expect(result).toEqual([]);
		});

		it('should propagate errors from BigQuery', async () => {
			mockQuery.mockRejectedValueOnce(new Error('BigQuery connection failed'));

			await expect(service.fetchStyleCopurchases()).rejects.toThrow(
				'BigQuery connection failed',
			);
		});
	});

	describe('fetchTrendingItemsOrderData', () => {
