import { Injectable, Logger, OnModuleInit } from '@nestjs/common';
import {
	algoliasearch,
	GetRecommendationsResponse,
	RecommendClient,
	SearchClient,
} from 'algoliasearch';

import { bufferedRollbar } from '@config/rollbar-buffer.config';

import { CacheService } from '@modules/cache/cache.service';
import { EnvConfigService } from '@modules/env-config/env-config.service';
import { MetricsService } from '@modules/metrics/metrics.service';

import { getEnv } from '@utils/get-env-variable.util';

import {
	ALGOLIA_OBJECT_ID_SUFFIXES,
	dailyTrackingKeys,
} from '@constants/common.constant';
import {
	ALG_API_KEY,
	ALG_APP_ID,
	ALG_INDEX_NAME,
	RELATED_PRODUCTS_CACHE_TTL,
} from '@constants/env-variables.constant';

import { AlgoliaRelatedProductHit } from '@interfaces/algolia-hits.interface';
import { Namespaces } from '@interfaces/cache.interface';

import { LogExecution } from '@decorators/log-execution.decorator';

@Injectable()
export class AlgoliaService implements OnModuleInit {
	private readonly logger = new Logger(AlgoliaService.name);

	constructor(
		private readonly cacheService: CacheService,
		private readonly configService: EnvConfigService,
		private readonly metricsService: MetricsService,
	) {}

	private algoliaClient: SearchClient;
	private algoliaClientRecommend: RecommendClient;
	private indexName: string;
	private relatedProductsCacheTtl: number;

	onModuleInit(): void {
		this.logger.log('Initializing Algolia client...');
		this.initializeAlgoliaClient();
		this.relatedProductsCacheTtl = this.configService.get<number>({
			key: RELATED_PRODUCTS_CACHE_TTL,
			converter: Number,
		});
	}

	private handleError({ context, error }: { context: string; error: unknown }): void {
		const err = error instanceof Error ? error : new Error(String(error));
		this.logger.error(`${context}: ${err.message}`, err.stack);
	}

	private initializeAlgoliaClient(): void {
		try {
			const appId = getEnv<string>({ key: ALG_APP_ID });
			const apiKey = getEnv<string>({ key: ALG_API_KEY });
			const indexName = getEnv<string>({ key: ALG_INDEX_NAME });

			if (!appId || !apiKey || !indexName) {
				throw new Error('Missing Algolia configuration');
			}

			const client = algoliasearch(appId, apiKey);

			this.algoliaClient = client;
			this.algoliaClientRecommend = client.initRecommend();
			this.indexName = indexName;

			this.logger.log('Algolia client initialized successfully');
		} catch (error: unknown) {
			this.handleError({ context: 'Failed to initialize Algolia client', error });
			throw new Error('Failed to initialize Algolia client');
		}
	}

	public async upsertObject({ object }: { object: { objectID: string } }): Promise<void> {
		try {
			await this.algoliaClient.saveObject({
				indexName: this.indexName,
				body: {
					...object,
				},
			});
			this.logger.log('Successfully upserted object to Algolia', {
				objectId: object.objectID,
				indexName: this.indexName,
			});
		} catch (error: unknown) {
			this.handleError({
				context: `Failed to upsert objects to Algolia index ${this.indexName}`,
				error,
			});
			throw new Error(`Failed to upsert objects to Algolia index ${this.indexName}`);
		}
	}

	public async deleteObject({ objectId }: { objectId: string }): Promise<void> {
		try {
			await this.algoliaClient.deleteObject({
				indexName: this.indexName,
				objectID: objectId,
			});
			this.logger.log('Successfully deleted object from Algolia', {
				objectId,
				indexName: this.indexName,
			});
		} catch (error: unknown) {
			this.handleError({
				context: `Failed to delete object ${objectId} from Algolia index ${this.indexName}`,
				error,
			});
			throw new Error(
				`Failed to delete object ${objectId} from Algolia index ${this.indexName}`,
			);
		}
	}

	public async saveObjects({
		objects,
	}: {
		objects: { objectID: string }[];
	}): Promise<void> {
		try {
			await this.algoliaClient.saveObjects({
				indexName: this.indexName,
				objects,
			});
			this.logger.log('Successfully saved objects to Algolia', {
				count: objects.length,
				indexName: this.indexName,
			});
		} catch (error: unknown) {
			this.handleError({
				context: `Failed to save objects to Algolia index ${this.indexName}`,
				error,
			});
			throw new Error(`Failed to save objects to Algolia index ${this.indexName}`);
		}
	}

	public async deleteObjects({ objectIds }: { objectIds: string[] }): Promise<void> {
		try {
			await this.algoliaClient.deleteObjects({
				indexName: this.indexName,
				objectIDs: objectIds,
			});
			this.logger.log('Successfully deleted objects from Algolia', {
				count: objectIds.length,
				indexName: this.indexName,
			});
		} catch (error: unknown) {
			this.handleError({
				context: `Failed to delete objects from Algolia index ${this.indexName}`,
				error,
			});
			throw new Error(`Failed to delete objects from Algolia index ${this.indexName}`);
		}
	}

	@LogExecution({
		paramFormatter: (params: { objectIdWithSuffix: string }) => ({
			objectIdWithSuffix: params.objectIdWithSuffix,
		}),
		responseFormatter: () => '',
	})
	async getAlgoliaRecommendations({
		objectIdWithSuffix,
	}: {
		objectIdWithSuffix: string;
	}): Promise<GetRecommendationsResponse> {
		return await this.algoliaClientRecommend.getRecommendations({
			requests: [
				{
					indexName: this.indexName,
					model: 'related-products',
					threshold: 0,
					objectID: objectIdWithSuffix,
				},
			],
		});
	}

	@LogExecution({
		logParams: false,
		responseFormatter: (response: { hits: AlgoliaRelatedProductHit[] }) => ({
			hitsCount: response.hits.map((hit) => hit.objectID),
		}),
	})
	async searchProducts({
		query = '',
		filters = '',
		hitsPerPage = 20,
	}: {
		query?: string;
		filters?: string;
		hitsPerPage?: number;
	}): Promise<{ hits: AlgoliaRelatedProductHit[] }> {
		try {
			const suffixFilter = `index_suffix:"${ALGOLIA_OBJECT_ID_SUFFIXES[0]}"`;
			const combinedFilters = filters ? `(${filters}) AND ${suffixFilter}` : suffixFilter;

			const searchResponse = await this.algoliaClient.search({
				requests: [
					{ indexName: this.indexName, query, filters: combinedFilters, hitsPerPage },
				],
			});

			const firstResult = searchResponse.results[0];
			if (firstResult && 'hits' in firstResult) {
				return {
					hits: firstResult.hits as AlgoliaRelatedProductHit[],
				};
			}

			return { hits: [] };
		} catch (error: unknown) {
			this.handleError({
				context: `Error searching products in Algolia with query "${query}" and filters "${filters}"`,
				error,
			});
			throw new Error(`Failed to search products in Algolia`);
		}
	}

	async getMultipleObjects({
		objectIDs,
	}: {
		objectIDs: string[];
	}): Promise<AlgoliaRelatedProductHit[]> {
		try {
			if (objectIDs.length === 0) {
				return [];
			}

			const results = await this.algoliaClient.getObjects({
				requests: objectIDs.map((objectID) => ({
					indexName: this.indexName,
					objectID: `${objectID}-${ALGOLIA_OBJECT_ID_SUFFIXES[0]}`,
				})),
			});

			return results.results.filter(
				(result): result is AlgoliaRelatedProductHit => result !== null,
			);
		} catch (error: unknown) {
			this.handleError({
				context: `Error fetching multiple objects from Algolia with IDs: ${objectIDs.join(', ')}`,
				error,
			});
			throw new Error(`Failed to fetch multiple objects from Algolia`);
		}
	}

	generateAlgoliaRelatedProductKey({ productId }: { productId: string }): string {
		return `style:${productId}`;
	}

	@LogExecution({
		logParams: false,
		responseFormatter: (response: number[]) => ({ relatedProductIds: response }),
	})
	public async getRelatedProductIds({
		productId,
	}: {
		productId: number;
	}): Promise<number[]> {
		try {
			const objectIdKey = `${productId}-${ALGOLIA_OBJECT_ID_SUFFIXES[0]}`;
			const cacheKey = `ids:${this.generateAlgoliaRelatedProductKey({ productId: objectIdKey })}`;
			const cachedIds = await this.cacheService.get<number[]>({
				namespace: Namespaces.RELATED_ITEMS_MODEL,
				key: cacheKey,
			});

			if (cachedIds) {
				this.logger.debug('Cache hit for related product IDs', {
					productId,
					objectIdKey,
				});
				await this.metricsService.incrementDailyCounter({
					metricType: dailyTrackingKeys.CACHE_REQUESTS,
				});
				return cachedIds;
			}

			this.logger.debug('Cache miss for related product IDs', { productId, objectIdKey });

			const results = await this.algoliaClientRecommend.getRecommendations({
				requests: [
					{
						indexName: this.indexName,
						model: 'related-products',
						threshold: 0,
						objectID: objectIdKey,
					},
				],
			});

			const recommendationsHits = results.results[0]?.hits ?? [];
			const styleIds = recommendationsHits
				.map((hit) => {
					const productIdValue = (hit as unknown as AlgoliaRelatedProductHit).product_id;
					return typeof productIdValue === 'string'
						? Number(productIdValue)
						: productIdValue;
				})
				.filter((id): id is number => !isNaN(id));

			await this.metricsService.incrementDailyCounter({
				metricType: dailyTrackingKeys.ALGOLIA_REQUESTS,
			});
			this.logger.debug('Fetched related product IDs from Algolia', {
				productId,
				objectIdKey,
				count: styleIds.length,
			});

			await this.cacheService.set({
				namespace: Namespaces.RELATED_ITEMS_MODEL,
				key: cacheKey,
				value: styleIds,
				ttl: this.relatedProductsCacheTtl,
			});

			return styleIds;
		} catch (error: unknown) {
			this.handleError({
				context: `Error fetching related product IDs from Algolia for productId ${productId}`,
				error,
			});
			if ((error as Error).message !== 'ObjectID does not exist') {
				bufferedRollbar.error({ err: error as Error, context: { productId } });
			}
			throw new Error(`Failed to fetch related product IDs for productId ${productId}`);
		}
	}

	async getProductsByMultipleBrands({
		brands,
		limit = 100,
		categoryId,
	}: {
		brands: string[];
		limit?: number;
		categoryId?: number | undefined;
	}): Promise<AlgoliaRelatedProductHit[]> {
		try {
			if (brands.length === 0) {
				return [];
			}

			const brandFilters = brands.map((brand) => `brand:"${brand}"`).join(' OR ');
			const suffixFilter = `index_suffix:"${ALGOLIA_OBJECT_ID_SUFFIXES[0]}"`;
			const categoryFilter = categoryId ? `primary_category_id:${categoryId}` : '';
			const combinedFilters = categoryFilter
				? `(${brandFilters}) AND ${categoryFilter} AND ${suffixFilter}`
				: `(${brandFilters}) AND ${suffixFilter}`;

			const result = await this.algoliaClient.searchForHits({
				requests: [
					{ indexName: this.indexName, filters: combinedFilters, hitsPerPage: limit },
				],
			});

			return (result.results[0]?.hits ?? []) as unknown as AlgoliaRelatedProductHit[];
		} catch (error: unknown) {
			this.handleError({
				context: `Error fetching products for brands: ${brands.join(', ')}`,
				error,
			});
			throw new Error(`Failed to fetch products for multiple brands`);
		}
	}
}
